def normalize(row: dict) -> str:
    if 'email' not in row:
        if DEBUG:
            print('locals_safe', {'id': row.get('id')})
        raise KeyError('email')
    return row['email']

try:
    print(normalize({"id": "C009"}))
except KeyError as e:
