def parse_dni(d: str) -> str:
    if not (d.isdigit() and len(d) == 8):
        raise ValueError(f"dni inválido: {d!r}")
    return d

fixture = ["12345678", "123", "87654321", "12AB5678"]
minimal = None
for d in fixture:
    try:
        parse_dni(d)
    except ValueError:
        minimal = d
        break
print(f"minimal={minimal!r}")

def bad_title(s: str) -> str:
    return s.title()

def good_title(s: str) -> str:
    particles = {'de', 'del', 'la', 'las', 'los', 'y'}
    parts = s.split()
    out = []
    for i, p in enumerate(parts):
        low = p.casefold()
        if i > 0 and low in particles:
            out.append(low)
        else:
            out.append(p[:1].upper() + p[1:].lower() if p else p)
    return ' '.join(out)

def test(fn):
    out = fn("juan de la cruz")
    assert out == "Juan de la Cruz", out
    return "pass"

try:
    test(bad_title)
    print('RED unexpected pass')
except AssertionError:
    print('RED')
print('GREEN', test(good_title))

def repo_save(corr, item):
    print(f"repo corr={corr} id={item.get('id')}")
    return True

def service_upsert(corr, item):
    print(f"service corr={corr}")
    return repo_save(corr, item)

def cli_main(corr, item):
    print(f"cli corr={corr}")
    return service_upsert(corr, item)

cli_main("corr-42", {"id": "C001"})

def process_batch(rows):
    ok, q = [], []
    for r in rows:
        if not r.get("id"):
            q.append({"row": r, "reason": "data:missing_id"})
        else:
            ok.append(r)
    return {"ok": ok, "quarantined": q, "in": len(rows)}

rows = [{"id": 1}, {}, {"id": 2}]
r = process_batch(rows)
assert r["in"] == len(r["ok"]) + len(r["quarantined"])
print('ok', len(r['ok']), 'quarantined', len(r['quarantined']), 'in', r['in'])

retry = {
    "TimeoutError": "yes",
    "ValueError": "no",
    "ConnectionError": "yes",
    "KeyError": "no",
    "PermissionError": "no",
}
for e, r in retry.items():
    print(f"{e}: {r}")

def retry_call(fn, max_attempts=3):
    last = None
    for attempt in range(1, max_attempts + 1):
        try:
            return fn()
        except TimeoutError as e:
            last = e
            if attempt == max_attempts:
                raise
    raise last

n = {"c": 0}

def flaky():
    n["c"] += 1
    if n["c"] < 3:
        raise TimeoutError("x")
    return "done"

print(retry_call(flaky), "calls", n["c"])
